// // This module compares a 5-bit input voltage with a reference voltage of 10 (in decimal). If the input voltage is less than or equal to the reference voltage, the output will be 1; otherwise, it will be 0.
module voltage_sensor (
    input [4:0] voltage_input,
    output reg is_high
);
    parameter REF_VOLTAGE = 10;

    always @* begin
        if (voltage_input > REF_VOLTAGE) 
            is_high = 1;
        else 
            is_high = 0;
    end
endmodule
